const express = require('express');
const crypto = require('crypto');

const app = express();
app.use(express.json());

const PORT = process.env.PORT || 3000;
const API_SECRET = process.env.API_SECRET || 'change-me';

const rewardConfig = {
  1: { coins: 100, gems: 0 },
  2: { coins: 150, gems: 0 },
  3: { coins: 200, gems: 1 },
  4: { coins: 250, gems: 1 },
  5: { coins: 300, gems: 2 }
};

const playerStore = new Map();

function getPlayer(playerId) {
  if (!playerStore.has(playerId)) {
    playerStore.set(playerId, {
      id: playerId,
      levels: {},
      balances: { coins: 0, gems: 0 },
      claimed: {}
    });
  }
  return playerStore.get(playerId);
}

function signPayload(payload) {
  return crypto.createHmac('sha256', API_SECRET).update(JSON.stringify(payload)).digest('hex');
}

function sanitizeNumber(value, min = 0, max = Number.MAX_SAFE_INTEGER) {
  const n = Number(value);
  if (!Number.isFinite(n)) return null;
  return Math.max(min, Math.min(max, Math.floor(n)));
}

app.post('/api/level-complete', (req, res) => {
  const { playerId, levelId, score, timeSeconds, clientSignature } = req.body || {};

  if (!playerId || levelId == null) {
    return res.status(400).json({ error: 'playerId and levelId are required' });
  }

  const normalizedLevelId = sanitizeNumber(levelId, 1, 1000000);
  const normalizedScore = sanitizeNumber(score, 0, 1000000000);
  const normalizedTime = sanitizeNumber(timeSeconds, 1, 1000000);

  if (normalizedLevelId == null || normalizedScore == null || normalizedTime == null) {
    return res.status(400).json({ error: 'Invalid numeric values' });
  }

  const payload = {
    playerId: String(playerId),
    levelId: normalizedLevelId,
    score: normalizedScore,
    timeSeconds: normalizedTime
  };

  const expectedSignature = signPayload(payload);
  const trusted = clientSignature && clientSignature === expectedSignature;

  const player = getPlayer(String(playerId));
  const best = player.levels[normalizedLevelId] || { bestScore: 0, bestTime: Number.MAX_SAFE_INTEGER, completed: false };

  const rewardTier = rewardConfig[normalizedLevelId] || {
    coins: Math.max(25, Math.floor(normalizedScore / 100)),
    gems: normalizedScore >= 5000 ? 1 : 0
  };

  const scoreBonus = Math.floor(normalizedScore / 1000);
  const timeBonus = normalizedTime <= 60 ? 2 : normalizedTime <= 120 ? 1 : 0;
  const reward = {
    coins: rewardTier.coins + scoreBonus + timeBonus,
    gems: rewardTier.gems
  };

  const isNewBest = normalizedScore > best.bestScore || normalizedTime < best.bestTime;
  const alreadyCompleted = best.completed === true;

  const record = {
    levelId: normalizedLevelId,
    score: normalizedScore,
    timeSeconds: normalizedTime,
    completedAt: new Date().toISOString(),
    trusted,
    rewardGranted: reward,
    newBest: isNewBest
  };

  player.levels[normalizedLevelId] = {
    bestScore: Math.max(best.bestScore, normalizedScore),
    bestTime: Math.min(best.bestTime, normalizedTime),
    completed: true,
    lastCompletion: record
  };

  if (trusted && (!alreadyCompleted || isNewBest)) {
    player.balances.coins += reward.coins;
    player.balances.gems += reward.gems;
  }

  return res.json({
    success: true,
    trusted,
    level: record,
    balances: player.balances,
    message: trusted
      ? (alreadyCompleted ? 'Level updated and rewards processed' : 'Level completed and rewards processed')
      : 'Level completion recorded; rewards pending verification'
  });
});

app.post('/api/claim-reward', (req, res) => {
  const { playerId, rewardId, clientSignature } = req.body || {};

  if (!playerId || !rewardId) {
    return res.status(400).json({ error: 'playerId and rewardId are required' });
  }

  const player = getPlayer(String(playerId));
  const claimKey = String(rewardId);

  if (player.claimed[claimKey]) {
    return res.status(409).json({ error: 'Reward already claimed' });
  }

  const payload = {
    playerId: String(playerId),
    rewardId: claimKey
  };

  const expectedSignature = signPayload(payload);
  const trusted = clientSignature && clientSignature === expectedSignature;

  let reward = null;

  if (claimKey.startsWith('daily_')) {
    reward = { coins: 50, gems: 1 };
  } else if (claimKey.startsWith('level_')) {
    const levelId = sanitizeNumber(claimKey.split('_')[1], 1, 1000000);
    const levelData = player.levels[levelId];
    if (!levelData || !levelData.completed) {
      return res.status(400).json({ error: 'Level not completed' });
    }
    reward = {
      coins: 20 + Math.floor((levelData.lastCompletion?.score || 0) / 2000),
      gems: levelData.lastCompletion?.score >= 10000 ? 1 : 0
    };
  } else if (claimKey.startsWith('promo_')) {
    reward = { coins: 100, gems: 5 };
  } else {
    reward = { coins: 10, gems: 0 };
  }

  if (trusted) {
    player.balances.coins += reward.coins;
    player.balances.gems += reward.gems;
    player.claimed[claimKey] = {
      claimedAt: new Date().toISOString(),
      reward
    };
  }

  return res.json({
    success: true,
    trusted,
    reward: trusted ? reward : null,
    balances: player.balances,
    message: trusted ? 'Reward claimed' : 'Reward claim recorded; pending verification'
  });
});

app.get('/api/player/:playerId', (req, res) => {
  const player = getPlayer(String(req.params.playerId));
  res.json(player);
});

app.get('/api/signature', (req, res) => {
  const { playerId, levelId, score, timeSeconds, rewardId } = req.query;

  let payload;
  if (rewardId != null) {
    payload = { playerId: String(playerId || ''), rewardId: String(rewardId) };
  } else {
    payload = {
      playerId: String(playerId || ''),
      levelId: sanitizeNumber(levelId, 1, 1000000),
      score: sanitizeNumber(score, 0, 1000000000),
      timeSeconds: sanitizeNumber(timeSeconds, 1, 1000000)
    };
  }

  res.json({ signature: signPayload(payload), payload });
});

app.get('/health', (req, res) => {
  res.json({ ok: true });
});

app.listen(PORT, () => {
  console.log(`API listening on port ${PORT}`);
});